class Repos(models.Model):
    """A repository — belongs to an [`Org`] via a single-column FK, and is the
composite-key target that both [`Issue`] and [`Label`] key on."""
    id = models.TextField(primary_key=True, help_text="The repo id (`org/name`).")
    org = models.ForeignKey("Orgs", on_delete=models.DO_NOTHING, db_column="org", related_name="repos_org", help_text="The owning org — a single-column to-one FK.")
    name = models.TextField(help_text="The short repo name.")
    is_private = models.BooleanField(help_text="Whether the repo is private.")

    class Meta:
        managed = False
        db_table = "repos"

